stories.description:
Users can export any theme from Settings → Theme to a `.todoozy-theme.json` file and import theme files back into the app. Both flows live as inline icon buttons next to the theme selector. Exports always bundle both the dark and light counterparts of a theme pair into one file. Imports always create both counterparts. Name collisions auto-resolve with an `(Imported)` suffix. Imported themes are treated as custom (`is_builtin: 0`) and flow through the existing sync path.

---

## 1. Add `fs:showSaveDialog` and `fs:readFile` IPC handlers

**File:** `src/main/ipc-handlers.ts`

The `fs:showOpenDialog` handler is at lines 883–891, just before the closing `}` of `registerIpcHandlers()` on line 892. `dialog` is imported on line 1; `writeFileSync` and `readFileSync` on line 2. Add these two handlers directly after line 891, before the closing `}`:

```typescript
ipcMain.handle('fs:showSaveDialog', async (_e, options: { defaultPath?: string; contents: string }) => {
  const win = getMainWindow()
  if (!win) return { canceled: true }
  const result = await dialog.showSaveDialog(win, {
    defaultPath: options.defaultPath,
    filters: [{ name: 'ToDoozy Theme', extensions: ['json'] }],
    title: 'Export theme'
  })
  if (result.canceled || !result.filePath) return { canceled: true }
  try {
    writeFileSync(result.filePath, options.contents, 'utf8')
    return { canceled: false, filePath: result.filePath }
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Write failed'
    return { canceled: false, error: message }
  }
})

ipcMain.handle('fs:readFile', async (_e, filePath: string) => {
  try {
    const contents = readFileSync(filePath, 'utf8')
    return { ok: true, contents }
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Read failed'
    return { ok: false, error: message }
  }
})
```

